// Helper 1: Returns full seconds float (Kept for consistency, but we won't use it for pproTicks anymore)
function timeToSecondsFloat(timeString) {
  if (!timeString) return 0;


  const dotTime = timeString.replace(',', '.');
  const parts = dotTime.split(':');

  // --- TIME FORMAT CHECKER AND CORRECTION ---
    if (parts.length === 2) {
        // Format is likely "MM:SS,mmm". Prepend "00" for hours.
        parts.unshift("00"); // parts is now ["00", "MM", "SS,mmm"]
    } else if (parts.length === 1) {
        // Format is likely "SS,mmm". Prepend "00:00" for hours and minutes.
        parts.unshift("00", "00"); // parts is now ["00", "00", "SS,mmm"]
    } else if (parts.length !== 3) {
        // Invalid or unexpected format
        console.error(`Invalid time string format: ${timeString}`);
        return 0;
    }
    // --- END CORRECTION ---
  return (parseFloat(parts[0]) * 3600) + 
         (parseFloat(parts[1]) * 60) + 
         parseFloat(parts[2]);
}

// Helper 2: Returns precise frame integer using seconds + ms calculation
function timeToFrameInteger(timeString, timebase) {
    if (!timeString) return 0;

    let parts = timeString.split(':');

    // --- TIME FORMAT CHECKER AND CORRECTION ---
    if (parts.length === 2) {
        // Format is likely "MM:SS,mmm". Prepend "00" for hours.
        parts.unshift("00"); // parts is now ["00", "MM", "SS,mmm"]
    } else if (parts.length === 1) {
        // Format is likely "SS,mmm". Prepend "00:00" for hours and minutes.
        parts.unshift("00", "00"); // parts is now ["00", "00", "SS,mmm"]
    } else if (parts.length !== 3) {
        // Invalid or unexpected format
        console.error(`Invalid time string format: ${timeString}`);
        return 0;
    }
    // --- END CORRECTION ---

    // parts is guaranteed to be ["HH", "MM", "SS,mmm"] at this point
    const ss_ms = parts[2].split(',');   

    // 1. Calculate total seconds portion (HH:MM:SS)
    const h = parseInt(parts[0]);
    const m = parseInt(parts[1]);
    const s = parseInt(ss_ms[0]);
    const baseSec = (h * 3600) + (m * 60) + s;

    // 2. Calculate ms portion (mmm)
    const ms = parseInt(ss_ms[1]) || 0;

    // Calculate frames separately and sum them up
    const framesFromSeconds = baseSec * timebase;

    // Calculate fractional frame and round
    const framesFromMs = Math.round((ms / 1000) * timebase);

    // Note: The -13 correction is preserved from your original code.
    return (framesFromSeconds + framesFromMs); 
}
