  const rawName =  item.json.name || '';
  const rawContent = item.json.text_content || ''; 

  // --- 1. Clean the Text Content (script) ---

  let cleanedScript = rawContent;

  // 1a. Remove URLs (common patterns for HTTP/HTTPS/drive links)
  // This Regex targets common URL structures (e.g., https://...)
  const urlRegex = /(https?:\/\/[^\s]+|www\.[^\s]+)/g;
  cleanedScript = cleanedScript.replace(urlRegex, '').trim();

  // 1b. Remove emoticons/emojis (Unicode ranges for common emojis)
  // This Regex targets various common emoji ranges and symbols.
  // Note: This is an extensive list and might not catch 100% of all rare Unicode symbols.
  const emojiRegex = /(\u00a9|\u00ae|[\u2000-\u3300]|\ud83c[\ud000-\udfff]|\ud83d[\ud000-\udfff]|\ud83e[\ud000-\udfff])/g;
  cleanedScript = cleanedScript.replace(emojiRegex, '').trim();

  // 1c. Remove all text contained within brackets () or []
  // This Regex targets anything between ( ) or [ ] globally (non-greedy match).
  const bracketRegex = /[\(\[].*?[\)\]]/g;
  cleanedScript = cleanedScript.replace(bracketRegex, '').trim();

  // 1d. Final cleanup: Remove unwanted characters (like leftover '\n' or consecutive spaces)
  cleanedScript = cleanedScript.replace(/[\n\t\r]+/g, ' '); // Replace newlines/tabs with space
  cleanedScript = cleanedScript.replace(/\s{2,}/g, ' ').trim(); // Collapse multiple spaces

  // --- 2. Clean the Name Field ---

  // For the name, just remove leading identifiers (e.g., "250501 ") and extra spaces.
  let cleanedName = rawName.replace(/^\s*\d+\s*/, '').trim(); 

